    90			}
    91		}
    92	
    93		// Collect and sort migration files.
    94		entries, err := fs.ReadDir(upMigrations, "schema")
    95		if err != nil {
    96			return 0, fmt.Errorf("reading embedded migrations: %w", err)
    97		}
    98	
    99		type migrationFile struct {
   100			version int
   101			name    string
   102		}
   103	
   104		var pending []migrationFile
   105		for _, e := range entries {
   106			if e.IsDir() || !strings.HasSuffix(e.Name(), ".up.sql") {
   107				continue
   108			}
   109			v, err := parseVersion(e.Name())
   110			if err != nil {
   111				return 0, fmt.Errorf("parsing migration filename %q: %w", e.Name(), err)
   112			}
   113			if v > current {
   114				pending = append(pending, migrationFile{version: v, name: e.Name()})
   115			}
   116		}
   117	
   118		sort.Slice(pending, func(i, j int) bool { return pending[i].version < pending[j].version })
   119	
   120		if len(pending) == 0 {
   121			return 0, nil
   122		}
   123	
   124		// Apply each pending migration. The DSN has multiStatements=true,
   125		// so each file is executed as a single ExecContext call.
   126		for _, mf := range pending {
   127			data, err := upMigrations.ReadFile("schema/" + mf.name)
   128			if err != nil {
   129				return 0, fmt.Errorf("reading migration %s: %w", mf.name, err)
   130			}
   131	
   132			sql := strings.TrimSpace(string(data))
   133			if sql != "" {
   134				if _, err := tx.ExecContext(ctx, sql); err != nil {
   135					return 0, fmt.Errorf("migration %s failed: %w", mf.name, err)
   136				}
   137			}
