   139			if _, err := tx.ExecContext(ctx, "INSERT INTO schema_migrations (version) VALUES (?)", mf.version); err != nil {
   140				return 0, fmt.Errorf("recording migration %s: %w", mf.name, err)
   141			}
   142		}
   143	
   144		return len(pending), nil
   145	}
