   147	// backfillMigrations marks all known migrations as applied without executing them.
   148	// Used when a database is restored from a backup that predates the schema_migrations
   149	// tracking table — the schema is already correct, we just need to record that fact.
   150	func backfillMigrations(ctx context.Context, tx *sql.Tx) (int, error) {
   151		entries, err := fs.ReadDir(upMigrations, "schema")
   152		if err != nil {
   153			return 0, fmt.Errorf("reading embedded migrations for backfill: %w", err)
   154		}
   155	
   156		n := 0
   157		for _, e := range entries {
   158			if e.IsDir() || !strings.HasSuffix(e.Name(), ".up.sql") {
   159				continue
   160			}
   161			v, err := parseVersion(e.Name())
   162			if err != nil {
   163				return 0, fmt.Errorf("parsing migration filename %q: %w", e.Name(), err)
   164			}
   165			if _, err := tx.ExecContext(ctx, "INSERT IGNORE INTO schema_migrations (version) VALUES (?)", v); err != nil {
