   120	// TestHelperProcess is the subprocess entry point used by the multi-process
   121	// concurrency test. It is not a real test — it exits early unless the
   122	// BEADS_EMBEDDED_DOLT_HELPER env var is set.
   123	func TestHelperProcess(t *testing.T) {
   124		if os.Getenv("BEADS_EMBEDDED_DOLT_HELPER") != "1" {
   125			return
   126		}
   127	
   128		dir := os.Getenv("BEADS_EMBEDDED_DOLT_DIR")
   129		if dir == "" {
   130			t.Fatal("BEADS_EMBEDDED_DOLT_DIR not set")
   131		}
   132		iters, _ := strconv.Atoi(os.Getenv("BEADS_EMBEDDED_DOLT_ITERS"))
   133		if iters < 1 {
   134			iters = 5
   135		}
   136		procID := os.Getenv("BEADS_EMBEDDED_DOLT_PROC_ID")
   137	
   138		ctx := t.Context()
   139		database := "testdb"
   140	
   141		for i := 0; i < iters; i++ {
   142			func() {
   143				db, cleanup, err := embeddeddolt.OpenSQL(ctx, dir, database, "")
   144				if err != nil {
   145					t.Fatalf("OpenSQL failed: %v", err)
   146				}
   147				defer func() {
   148					if err := cleanup(); err != nil {
   149						t.Fatalf("cleanup failed: %v", err)
   150					}
   151				}()
   152	
   153				tag := fmt.Sprintf("proc_%s_iter_%d_pid_%d", procID, i, os.Getpid())
   154	
   155				// CREATE TABLE IF NOT EXISTS
   156				mustExec(t, db, ctx, `CREATE TABLE IF NOT EXISTS concurrency_test (
   157					id INT AUTO_INCREMENT PRIMARY KEY,
   158					tag VARCHAR(255) NOT NULL,
   159					value INT NOT NULL
   160				)`)
   161	
   162				// INSERT
   163				res := mustExec(t, db, ctx, "INSERT INTO concurrency_test (tag, value) VALUES (?, ?)", tag, i)
   164				rowID, err := res.LastInsertId()
   165				if err != nil {
   166					t.Fatalf("LastInsertId: %v", err)
   167				}
   168	
   169				// SELECT — verify the inserted row.
   170				var gotTag string
   171				var gotVal int
   172				if err := mustQueryRow(t, db, ctx, "SELECT tag, value FROM concurrency_test WHERE id = ?", rowID).Scan(&gotTag, &gotVal); err != nil {
   173					t.Fatalf("scan tag/value: %v", err)
   174				}
   175				if gotTag != tag || gotVal != i {
   176					t.Fatalf("data mismatch: got (%q, %d), want (%q, %d)", gotTag, gotVal, tag, i)
   177				}
   178	
   179				// UPDATE
   180				mustExec(t, db, ctx, "UPDATE concurrency_test SET value = ? WHERE id = ?", i+1000, rowID)
   181	
   182				// DELETE
   183				mustExec(t, db, ctx, "DELETE FROM concurrency_test WHERE id = ?", rowID)
   184	
   185				// Verify row is gone.
   186				var count int
   187				if err := mustQueryRow(t, db, ctx, "SELECT COUNT(*) FROM concurrency_test WHERE id = ?", rowID).Scan(&count); err != nil {
   188					t.Fatalf("scan count: %v", err)
   189				}
   190				if count != 0 {
   191					t.Fatalf("row not deleted: id=%d still present", rowID)
   192				}
   193			}()
   194		}
   195	
   196		fmt.Println("OK")
   197	}
