   214	// TestConcurrentNewReturnsError verifies that opening a second EmbeddedDoltStore
   215	// on the same data directory returns a clear error instead of panicking with a
   216	// nil-pointer dereference in the embedded Dolt engine (GH#2571).
   217	func TestConcurrentNewReturnsError(t *testing.T) {
   218		if os.Getenv("BEADS_TEST_EMBEDDED_DOLT") != "1" {
   219			t.Skip("set BEADS_TEST_EMBEDDED_DOLT=1 to run embedded dolt concurrency tests")
   220		}
   221	
   222		ctx := t.Context()
   223		beadsDir := t.TempDir()
   224	
   225		// First store opens successfully and holds the exclusive flock.
   226		store1, err := embeddeddolt.New(ctx, beadsDir, "testdb", "main")
   227		if err != nil {
   228			t.Fatalf("first New: %v", err)
   229		}
   230		defer store1.Close()
   231	
   232		// Second store on the same directory must fail with a lock error, not panic.
   233		store2, err := embeddeddolt.New(ctx, beadsDir, "testdb", "main")
   234		if err == nil {
   235			store2.Close()
   236			t.Fatal("second New succeeded; expected lock contention error")
   237		}
   238		if !strings.Contains(err.Error(), "another process holds the exclusive lock") {
   239			t.Fatalf("unexpected error from second New: %v", err)
   240		}
   241		t.Logf("second New correctly returned: %v", err)
   242	
   243		// After closing the first store, a third open must succeed.
   244		store1.Close()
   245		store3, err := embeddeddolt.New(ctx, beadsDir, "testdb", "main")
   246		if err != nil {
   247			t.Fatalf("third New (after close): %v", err)
   248		}
   249		store3.Close()
   250	}
