   252	// TestWithLockBypassesDoubleLock verifies that WithLock allows the caller to
   253	// supply a pre-acquired lock so New does not attempt a second flock (which
   254	// would fail on macOS where flock is per-fd, not per-process).
   255	func TestWithLockBypassesDoubleLock(t *testing.T) {
   256		if os.Getenv("BEADS_TEST_EMBEDDED_DOLT") != "1" {
   257			t.Skip("set BEADS_TEST_EMBEDDED_DOLT=1 to run embedded dolt concurrency tests")
   258		}
   259	
   260		ctx := t.Context()
   261		beadsDir := t.TempDir()
   262		dataDir := filepath.Join(beadsDir, "embeddeddolt")
   263	
   264		// Acquire the lock externally (as bd init does).
   265		lock, err := embeddeddolt.TryLock(dataDir)
   266		if err != nil {
   267			t.Fatalf("TryLock: %v", err)
   268		}
   269		defer lock.Unlock()
   270	
   271		// New with WithLock must succeed without double-locking.
   272		store, err := embeddeddolt.New(ctx, beadsDir, "testdb", "main", embeddeddolt.WithLock(lock))
   273		if err != nil {
   274			t.Fatalf("New with WithLock: %v", err)
   275		}
   276		// Close must NOT release the caller-supplied lock.
   277		store.Close()
   278	
   279		// The lock should still be held — verify by trying to lock again (should fail).
   280		_, err = embeddeddolt.TryLock(dataDir)
   281		if err == nil {
   282			t.Fatal("TryLock succeeded after Close; expected lock to still be held by caller")
   283		}
   284	}
