   310	func mustFindModuleRoot(t *testing.T) string {
   311		t.Helper()
   312		_, thisFile, _, ok := runtime.Caller(0)
   313		if !ok {
   314			t.Fatal("runtime.Caller failed")
   315		}
   316		dir := filepath.Dir(thisFile)
   317		for {
   318			if _, err := os.Stat(filepath.Join(dir, "go.mod")); err == nil {
   319				return dir
   320			}
   321			next := filepath.Dir(dir)
   322			if next == dir {
   323				t.Fatalf("could not find module root from %q", thisFile)
   324			}
   325			dir = next
   326		}
   327	}
