    11	// DetectCyclesInTx finds dependency cycles across both the dependencies and
    12	// wisp_dependencies tables. Returns slices of issues forming each cycle.
    13	// Only considers "blocks" and "conditional-blocks" dependencies for cycle detection.
    14	//
    15	//nolint:gosec // G201: depTable is hardcoded to "dependencies" or "wisp_dependencies"
    16	func DetectCyclesInTx(ctx context.Context, tx *sql.Tx) ([][]*types.Issue, error) {
    17		// Build adjacency list from both dependency tables.
    18		graph := make(map[string][]string)
    19	
    20		for _, depTable := range []string{"dependencies", "wisp_dependencies"} {
    21			rows, err := tx.QueryContext(ctx, fmt.Sprintf(`
    22				SELECT issue_id, depends_on_id, type
    23				FROM %s
    24			`, depTable))
    25			if err != nil {
    26				return nil, fmt.Errorf("detect cycles: query %s: %w", depTable, err)
    27			}
    28			for rows.Next() {
    29				var issueID, dependsOnID, depType string
    30				if err := rows.Scan(&issueID, &dependsOnID, &depType); err != nil {
    31					_ = rows.Close()
    32					return nil, fmt.Errorf("detect cycles: scan %s: %w", depTable, err)
    33				}
    34				if types.DependencyType(depType) == types.DepBlocks || types.DependencyType(depType) == types.DepConditionalBlocks {
    35					graph[issueID] = append(graph[issueID], dependsOnID)
    36				}
    37			}
    38			_ = rows.Close()
    39			if err := rows.Err(); err != nil {
    40				return nil, fmt.Errorf("detect cycles: rows %s: %w", depTable, err)
    41			}
    42		}
    43	
    44		// Find cycles using DFS.
    45		var cycles [][]*types.Issue
    46		visited := make(map[string]bool)
    47		recStack := make(map[string]bool)
    48		path := make([]string, 0)
    49	
    50		var dfs func(node string) bool
    51		dfs = func(node string) bool {
    52			visited[node] = true
    53			recStack[node] = true
    54			path = append(path, node)
    55	
    56			for _, neighbor := range graph[node] {
    57				if !visited[neighbor] {
    58					if dfs(neighbor) {
    59						return true
    60					}
    61				} else if recStack[neighbor] {
    62					// Found cycle — extract it.
    63					cycleStart := -1
    64					for i, n := range path {
    65						if n == neighbor {
    66							cycleStart = i
    67							break
    68						}
    69					}
    70					if cycleStart >= 0 {
    71						cyclePath := path[cycleStart:]
    72						var cycleIssues []*types.Issue
    73						for _, id := range cyclePath {
    74							issue, _ := GetIssueInTx(ctx, tx, id)
    75							if issue != nil {
    76								cycleIssues = append(cycleIssues, issue)
    77							}
    78						}
    79						if len(cycleIssues) > 0 {
    80							cycles = append(cycles, cycleIssues)
    81						}
    82					}
    83				}
    84			}
    85	
    86			path = path[:len(path)-1]
    87			recStack[node] = false
    88			return false
    89		}
    90	
    91		for node := range graph {
    92			if !visited[node] {
    93				dfs(node)
    94			}
    95		}
    96	
    97		return cycles, nil
